y-content:space-between;font-size:13px"><span style="color:#7f8c8d">Investment:</span><span style="font-weight:600">$<?php echo number_format($channel['investment']);?></span></div><div style="display:flex;justify-content:space-between;font-size:13px;margin-top:5px"><span style="color:#7f8c8d">Revenue:</span><span style="font-weight:600;color:#27ae60">$<?php echo number_format($channel['revenue']);?></span></div></div><div class="channel-metrics"><div class="metric"><div class="value">$<?php echo number_format($channel['cost_per_hire']);?></div><div class="label">Cost/Hire</div></div><div class="metric"><div class="value"><?php echo $channel['applications'];?></div><div class="label">Applications</div></div><div class="metric"><div class="value"><?php echo $channel['conversion_rate'];?>%</div><div class="label">Conversion</div></div><div class="metric"><div class="value"><i class="fas fa-arrow-<?php echo $channel['trend']=='up'?'up':'down';?>" style="color:<?php echo $channel['trend']=='up'?'#27ae60':'#e74c3c';?>"></i></div><div class="label">Trend</div></div></div></div><?php endforeach;?></div></div><div class="section"><h2><i class="fas fa-rocket"></i> Top Performing Campaigns</h2><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse"><thead><tr style="background:#f8f9fa"><th style="padding:12px;text-align:left;border-bottom:2px solid #dee2e6">Campaign</th><th style="padding:12px;text-align:left;border-bottom:2px solid #dee2e6">Channel</th><th style="padding:12px;text-align:center;border-bottom:2px solid #dee2e6">Investment</th><th style="padding:12px;text-align:center;border-bottom:2px solid #dee2e6">Revenue</th><th style="padding:12px;text-align:center;border-bottom:2px solid #dee2e6">ROI</th><th style="padding:12px;text-align:center;border-bottom:2px solid #dee2e6">Hires</th><th style="padding:12px;text-align:center;border-bottom:2px solid #dee2e6">Status</th></tr></thead><tbody><?php foreach($campaigns as $campaign):?><tr style="border-bottom:1px solid #ecf0f1"><td style="padding:12px"><?php echo $campaign['campaign_name'];?></td><td style="padding:12px"><?php echo $campaign['channel'];?></td><td style="padding:12px;text-align:center">$<?php echo number_format($campaign['investment']);?></td><td style="padding:12px;text-align:center;color:#27ae60;font-weight:600">$<?php echo number_format($campaign['revenue']);?></td><td style="padding:12px;text-align:center;font-weight:700;color:#f5576c"><?php echo $campaign['roi'];?>%</td><td style="padding:12px;text-align:center"><?php echo $campaign['hires'];?></td><td style="padding:12px;text-align:center"><span style="padding:4px 12px;border-radius:20px;font-size:12px;font-weight:600;background:<?php echo $campaign['status']=='Active'?'#d4edda':'#f8d7da';?>;color:<?php echo $campaign['status']=='Active'?'#155724':'#721c24';?>"><?php echo $campaign['status'];?></span></td></tr><?php endforeach;?></tbody></table></div></div><div style="text-align:center;margin-top:30px"><a href="<?php echo base_url('Roi_tracking/forecast');?>" class="btn btn-primary"><i class="fas fa-crystal-ball"></i> View Forecast</a><a href="<?php echo base_url('Sales_marketing');?>" class="btn btn-primary" style="background:#95a5a6;margin-left:10px"><i class="fas fa-arrow-left"></i> Back to Hub</a></div></div><script>const ctx=document.getElementById('roiTrendChart').getContext('2d');new Chart(ctx,{type:'line',data:{labels:<?php echo json_encode(array_column($trends['monthly'],'month'));?>,datasets:[{label:'ROI %',data:<?php echo json_encode(array_column($trends['monthly'],'roi'));?>,borderColor:'#f5576c',backgroundColor:'rgba(245,87,108,0.1)',tension:0.4,fill:true},{label:'Investment',data:<?php echo json_encode(array_column($trends['monthly'],'investment'));?>,borderColor:'#667eea',backgroundColor:'rgba(102,126,234,0.1)',tension:0.4,yAxisID:'y1'}]},options:{responsive:true,interaction:{mode:'index',intersect:false},scales:{y:{type:'linear',display:true,position:'left',title:{display:true,text:'ROI %'}},y1:{type:'linear',display:true,position:'right',title:{display:true,text:'Investment ($)'},grid:{drawOnChartArea:false}}}}});</script></body></html>
